proof fn det_ptr_mut_read<T>(ptr: *const T, pre_perm: PointsTo<T>, post1_perm: PointsTo<T>, r1: T, post2_perm: PointsTo<T>, r2: T)
    requires (pre_perm.ptr() == ptr), (pre_perm.is_init()),
    ensures
        ({
            &&& (post1_perm.ptr() == ptr)
            &&& (post1_perm.is_uninit())
            &&& (r1 == pre_perm.value())
            &&& (post2_perm.ptr() == ptr)
            &&& (post2_perm.is_uninit())
            &&& (r2 == pre_perm.value())
        }) ==> det_ptr_mut_read_equal::<T>(r1, r2, post1_perm, post2_perm),
{
{ASSUMES}}

